var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제프티 바이오테크 특무함 <color=#ffd34c>코러스</color>, 대표 전용 휴게실.\\n<color=#ffd34c>윌버 웨이틀리</color> 대표, 데이트 중","JPN":"ジェフティ・バイオテック特務艦<color=#ffd34c>コーラス</color>、代表専用休憩室。\\n<color=#ffd34c>ウィルバー・ウェイトリー</color>代表、デート中","ENG":"CEO Lounge Cabin, Jehuty Biotech Special Mission Ship\xA0<color=#ffd34c>Chorus</color>\\nCEO\xA0<color=#ffd34c>Wilbur Whateley</color> on a date\xA0","TWN":"傑夫堤生物科特務艦 <color=#ffd34c>Chorus</color>。代表專用休息室。\\n<color=#ffd34c>韋爾伯·韋特利</color>代表約會中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>탑승자들의 신원 조회를 마쳤습니다. 이륙 중 선체가 다소 흔들릴 수 있으니 주의해 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>搭乗者の身元照会が完了しました。離陸中に船体が多少揺れることがありますので、ご注意ください。</color>","ENG":"<color=#ffd34c>Passenger identification complete. Please note the cabin may experience some turbulence during takeoff.</color>","TWN":"<color=#ffd34c>乘客資料確認完畢。請注意，升空時船身會有點晃動的情形。</color>"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"차원함선에는 이런 시설도 있구나……. 직접 타 보는 건 처음이야…….","JPN":"次元艦船にこんな施設もあるのね……乗るのは初めて……","ENG":"Wow, so they've got all this fancy stuff on a dimensional ship… I've never actually been on one before…","TWN":"次元艦船中竟然還有這種設備……我還是第一次搭呢……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하. 앞으로는 원한다면 언제든지 탈 수 있을 거야.","JPN":"ハハ。これからは君が望むならいくらでも乗れるさ。","ENG":"Haha. From now on, you'll get to ride on one whenever you wish.","TWN":"哈哈～喜歡的話，之後你隨時想搭都沒問題！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"자, 포도주야. 목도 축일 겸 한 잔 마셔.","JPN":"さあ、ワインだ。気持ちを落ち着かせるためにも一杯飲もう。","ENG":"Here's some wine. Have a glass to quench your thirst.","TWN":"來，這是葡萄酒，喝一杯潤潤喉吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L8_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜 그래? 아까부터 안색이 나쁜데?","JPN":"どうしたんだ？　さっきから顔色が悪いみたいだが。","ENG":"What's wrong? You've been looking distressed for a while.","TWN":"怎麼了？你從剛才臉色就怪怪的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기네 연구소……. 폭발한 지 한참 지났는데 아직도 연기가 올라오고 있었어.","JPN":"ダーリンの研究所……爆発してから結構経ったのに未だに煙が上がってるの。","ENG":"Your lab… It's been hours since it blew up, but there's still smoke coming from it.","TWN":"親愛的研究所……已經爆炸一段時間了，怎麼都沒看到煙往上竄？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그야 그렇겠지. 이 일대에서는 제일 큰 연구 시설이었으니까.","JPN":"それはそうだろうな。この一帯では一番大きな研究施設だったから。","ENG":"Well, that's no surprise. It was the biggest research center in the area.","TWN":"喔～應該是因為那是這一帶最大的研究設施吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기는 분하지도 않아? 그 이상한 여자애가 폭발시킨 거라며?","JPN":"ダーリンは悔しくない？　あの変な子が爆発させたんでしょ？","ENG":"Aren't you even angry? Didn't you say that weird girl blew it up?","TWN":"親愛的你不生氣嗎？那個詭異的丫頭炸掉你的研究室欸？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"어렵게 만든 회사가 큰 손해를 보게 생겼는데……. 나만 챙겨 주고…….","JPN":"苦労して作った会社が大きな損害を受けたのに……私のことばかり気遣ってくれて……","ENG":"You've worked so hard to build this company… But you seem concerned only for me…","TWN":"你辛辛苦苦才建立起來的公司，結果遇到這麼大的虧損……你還只顧著我……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기가 걱정돼. 내가 안 보는 곳에서 많이 슬퍼할까 봐.","JPN":"ダーリンが心配なの。私の見てないところで落ち込んでるかもって。","ENG":"I'm worried about you, babe. Worried that you're really upset but trying to hide it around me.","TWN":"人家很擔心你，你不要自己眼淚往肚子裡吞。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"갑자기 이런 일에 휘말려서 정신이 없을 텐데, 넌 내 걱정부터 해 주는구나.","JPN":"急にこんなことに巻き込まれて困惑しているはずなのに、君は僕のことを心配してくれるんだね。","ENG":"It must be hectic for you to be embroiled in this mess… and yet you worry about me first.","TWN":"你突然捲進這種事應該很驚慌吧？結果你竟然先關心我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"고마워. 네가 옆에 없었더라면 어떻게 됐을지, 상상하기도 끔찍해.","JPN":"ありがとう。君がそばにいなかったらどうなっていたのか、想像したくもない。","ENG":"Thank you, darling. I'd hate to imagine what would have happened if I didn't have you by my side.","TWN":"謝謝親愛的，我真不敢想像，萬一你不在我身邊會怎樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"손해가 크겠지만 뭐 어때.","JPN":"損害は大きいけど、まあいいじゃないか。","ENG":"Sure, the company may take a big hit from this, but who cares?","TWN":"這些虧損算什麼！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"나한테는 자기가 있는데.","JPN":"君が側にいてくれるならそれだけでいいさ。","ENG":"As long as I have you.","TWN":"起碼我還有你！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야. 직원 분들도 계시잖아. 이런 데서 부끄럽게 키스는…….","JPN":"ダ、ダーリン。会社の方もいらっしゃるのに、こんなところでキスするのは恥ずかしいよ……","ENG":"Aww, babe… Your employees are still here. We can't be kissing like this…","TWN":"討厭～大家都在呢～你這樣親人家，人家會害羞……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"하하. 저희는 그냥 없는 사람이라고 생각하시죠.","JPN":"ハハ。俺たちはここに居ないものだと思ってください。","ENG":"Haha. Just pretend we're invisible, ma'am.","TWN":"哈哈，夫人就請當我們是塑膠吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MOB_HORIZON_NULL_NULL","text":{"KOREA":"대표님의 프라이버시인데 저희가 어디 가서 발설할 리 있겠습니까.","JPN":"代表のプライバシーですから、口外することはしません。","ENG":"We wouldn't dare go tattling about this. That would be an invasion of the boss's privacy.","TWN":"代表的隱私我們是不會洩漏出去的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그렇다는데, 어때?","JPN":"と言っているけど、どうだい？","ENG":"So they say… How about it?","TWN":"他們都這麼說了，你說呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"으응……. 그, 그럼 조금만…….","JPN":"じゃ、じゃあ……少しだけ……","ENG":"O-okay… Then just a little…","TWN":"嗯……那就一下下……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"분위기 좋은 와중에 잠시 실례해야겠어, 대표님.","JPN":"いい所で申し訳ないけどちょっと失礼するわね、代表。","ENG":"Sorry to break the rosy mood for a sec, boss.","TWN":"代表，不好意思打擾你們親熱。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나? 함교에 있어야 할 네가 왜 여기에 온 거냐?","JPN":"シェナ？　艦橋にいるはずのお前がなぜここに来たんだ？","ENG":"Shena? What are you doing here? Shouldn't you be on the bridge?","TWN":"世娜？你不是應該在艦橋嗎？來這裡幹嘛？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"호라이즌 때문이야.","JPN":"ホライズンのせいよ。","ENG":"It's about Horizon.","TWN":"還不是因為地平線～"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"대표님은 시설이 무너질 때 걔가 통제실에 있었다고 했지?","JPN":"代表は施設が崩壊する時、あの子が統制室にいたと言ってたわね？","ENG":"You said she was in the control room when the facility collapsed, right?","TWN":"代表你說過，設施瓦解時她在控制室裡對吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 시스템을 통해 마지막으로 전달 받은 CCTV에는 그렇게 찍혀 있었지.","JPN":"ああ、システムを通じて最後に報告してもらった監視カメラに映っていた。","ENG":"That's right. That's what I saw in the CCTV footage in the System's final transmission.","TWN":"沒錯，系統最後傳來的CCTV拍到她在裡面。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그 사채꾼이 내 예상을 뛰어넘었다는 사실은 인정해야겠어. 설마 어보미네이션을 쓰러뜨릴 줄은 나도 몰랐으니까.","JPN":"あの闇金野郎が僕の予想を越えていたという事実は\\n認める。まさかアボミネーションを倒すとは予想外だった。","ENG":"I've got to admit that loan shark went well beyond my expectations. I never imagined it could actually defeat the Abomination.","TWN":"那個放高利貸的算是顛覆我的三觀，我沒料到她竟然可以打倒憎惡。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하지만 그래봤자 기계는 기계일 뿐이지.","JPN":"しかし、機械は機械にすぎない。","ENG":"But in the end, a machine is just a machine.","TWN":"不過機器人終究是機器人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"지하 수백 미터 아래 파묻히고도 멀쩡히 기어나올 수 있을 리 없잖나.","JPN":"地下数百メートルの下に埋もれて、無事でいるはずがない。","ENG":"There's no way it could make it out unscathed from hundreds of meters underground.","TWN":"被埋在地下幾百公尺，怎麼可能從那麼深的地方爬起來？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふうん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"정말 그렇게 생각해, 대표님? 허세가 아니라?","JPN":"本当にそう思う？　虚勢じゃなくて？","ENG":"Do you really believe that, boss? Do you?","TWN":"代表你確定嗎？還是只是嘴硬？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥. 나야말로 네가 왜 그렇게 그 사채꾼을 신경 쓰는지 이해할 수 없군.","JPN":"ふん、お前こそ、なぜそこまであの闇金野郎を気にするのか理解できないな。","ENG":"Hmph. I don't understand why you're still concerned about that loan shark.","TWN":"哼！我才想問你咧，你為什麼那麼關心那個放高利貸的！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내 추궁을 듣고 두려워져서 괜히 위험성을 부풀리는 거 아닌가?","JPN":"僕に責任を追及されて怖くなって、わざと危険性を誇張してるんじゃないか？","ENG":"I'm inclined to think you're inflating her threat just to avoid my castigation.","TWN":"是不是怕我怪你辦事不力，所以才想嚇唬我她有多可怕？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네가 경호에 태만했다는 보고를 무마하려고?","JPN":"お前が警護を怠ったという報告をもみ消そうとしてな。","ENG":"To gloss over the admission of your own lax measures contributing to this mess.","TWN":"是不是怕我打你小報告？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 그렇게 받아들여지다니 조금 슬퍼지네. 나는 꽤 성실한 편이라고 자부하는데.","JPN":"フフッ。そう受けとられるなんてちょっと悲しくなったわ。自分で言うのもなんだけど、私ってかなり真面目な方なのよ。","ENG":"Haha. I'm almost disappointed you'd think that. I actually pride myself in my diligence.","TWN":"呵呵～你竟然是這樣想的，真是有點難過呢～我自認我滿盡責的說～"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그러면 내가 역으로 하나 물어 볼까? 대표님은 호라이즌이 뭐라고 생각해?","JPN":"じゃあ、逆に私から一つ聞いてみようかしら。代表はホライズンが何者だと思う？","ENG":"Let me ask you something. What do you think Horizon is?","TWN":"那可以換我問你一句嗎？你覺得地平線是什麼來頭？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하. 그야 당연히 로봇이지. 어떤 괴짜가 만든 커스텀 안드로이드.","JPN":"は？　そりゃあロボットだろう。とある変わり者が作ったカスタムアンドロイド。","ENG":"Ha. A robot, of course. A custom-made android created by some maniac.","TWN":"哈，啊不就是機器人，就是某個怪咖製造的人形機器人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어떤 괴짜가?","JPN":"変わり者？","ENG":"Which maniac?","TWN":"某個怪咖？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"말 돌리지 마라, 셰나. 나는 네 장난질에 어울려 줄 만큼 머리가 나쁘지 않아.","JPN":"はぐらかすな、シェナ。僕はお前の誘導尋問に付き合うほどバカじゃないぞ。","ENG":"Don't try to change the subject, Shena. I'm not dense enough to play along with your inane games.","TWN":"世娜，你少岔開話題，你以為我有笨到會被你帶風向嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇지만 조금은 궁금하지 않아?","JPN":"でも少しは気にならない？","ENG":"But aren't you at least a little bit curious?","TWN":"但你一點都不好奇嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어디서 저런 괴물 같은 성능을 가진 안드로이드를 만들 수 있는지 말이야.","JPN":"誰があんな化け物みたいな性能を持つアンドロイドを作り出したのか。","ENG":"I mean, who could have possibly created such a ridiculously powerful android?","TWN":"什麼地方可以製造出，那種有著如怪物般性能的人形機器人？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아니면, 우리 대표님은 상대에 대해 알면 겁먹을까 봐 일부러 모른 척 하는 걸까?","JPN":"それとも、うちの代表は相手について知ってしまったら怖くなるからと、わざと知らんぷりをするのかしら？","ENG":"Or are you just pretending not to care because you're too scared the truth will intimidate you?","TWN":"還是，代表是怕知道太多，你會越害怕，所以才故意裝傻嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"닥쳐!!","JPN":"黙れ！！","ENG":"Silence!!","TWN":"閉嘴！！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"누가 만들었는지가 뭐가 중요해!! 그 개망나니 계집애는 저 땅속에 처박혀 있는데!","JPN":"誰が作ったのかがそんなに重要か！？\\nどうせ今頃あのアバズレは瓦礫の下に埋まっているのに！","ENG":"It doesn't matter who created her!! That little brat is buried deep underground!","TWN":"是誰製造的很重要嗎！！那臭丫頭現在被埋在地底下好嗎！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"나한테 중요한 건 상부에 보고할 성과야! 멘탈 프린팅 기술의 완성이라고!","JPN":"僕にとって大事なのは上層部に報告する成果だけだ！　メンタル・プリンティング技術の完成なんだよ！","ENG":"All I care about is what I can report up the chain! The completion of the Mental Printing technology!","TWN":"對我而言，最重要的就是上面要看的結果！也就是完成智力複印技術！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그런데 저 빌어먹을 사채꾼이 작정하고 내 계획을 전부 망치려고 들었단 말이다!","JPN":"なのにあのクソ闇金野郎がここぞとばかりに計画を邪魔しやがって！","ENG":"But that damn loan shark set out to foil my plans!","TWN":"而那該死的高利貸想毀掉我的計畫！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"방해하는 놈은 내버려 두지 않아! 그딴 데 쓸 시간 있으면 코핀 컴퍼니를 박살낼 방법이나 찾아 와!","JPN":"これ以上の邪魔は許さない！　あんな鉄くずを気にする暇があるなら、コフィンカンパニーを潰す方法でも考えてこい！","ENG":"I won't let anyone get in my way! If you've got time to muse about such nonsense, go figure out how to destroy the Coffin Company!","TWN":"不能放過妨礙我的傢伙！你有時間想那些，不如好好想想要怎麼剷平科芬公司吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 그럼 코핀 컴퍼니에 신경 쓸 시간은 있고?","JPN":"フフッ。じゃあ、コフィンカンパニーに気を使う余裕はあるのね？","ENG":"Oh, so you ARE worried about Coffin Company?","TWN":"呵呵～你還有時間想科芬公司的事嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"꺄아아악?!","JPN":"きゃああっ！！","ENG":"Eeeek?!","TWN":"啊啊啊？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐지? 포격인가?","JPN":"なんだ？　砲撃か？","ENG":"What was that? Are we under attack?","TWN":"什麼東西？是砲擊嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"함교! 방금 함선이 흔들린 이유가 뭐냐! 보고해라!","JPN":"艦橋！　今艦船が揺れた理由を説明しろ！","ENG":"Come in, bridge! What caused that turbulence just now? Give me a SITREP!","TWN":"艦橋！剛剛艦船晃動的原因是什麼？立刻回答我！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"크, 큰일입니다! 대표님!","JPN":"た、大変です！　代表！","ENG":"I-it's an emergency, sir!","TWN":"代表，不好了！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"외부 카메라가 선체를 기어오르는 물체를 포착해 확인했습니다! 그, 그런데 그게……!","JPN":"外部カメラが船体をよじ登る物体を捉えました！　し、しかしそれが……！","ENG":"Our exterior cameras have spotted an object climbing across the hull! B-but it looks like…!","TWN":"剛剛鏡頭有拍到爬上船身的物體！是…是…！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호, 호라이즌……? 저 녀석이, 어떻게 함선에……?","JPN":"ホ、ホライズン……？　あいつ、どうやって艦船に……？","ENG":"H-Horizon…? How did that brat get on the ship?","TWN":"地…地平線…？那丫頭是怎麼……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음. 역시나. 기대를 빗나가지 않네.","JPN":"へえ、やっぱり。期待を裏切らないわね。","ENG":"Hmm... Just as I thought. She doesn't disappoint.","TWN":"嗯～不錯，沒有辜負我的期待。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭘 여유 부리고 앉았어!","JPN":"何余裕を見せてるんだ！","ENG":"Don't just sit there!","TWN":"你還在那裡悠哉什麼！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"당장 저 사채꾼을 끝장내 버려! 내 앞에서 입도 뻥긋 못할 고물로 만들어 버리란 말이다!","JPN":"今すぐあの闇金野郎を始末しろ！　バラバラにしてリサイクルもできないくず鉄にしろって言ってんだ！","ENG":"Get rid of that loan shark at once! Turn her into scrap metal so she'll never utter another word to me!","TWN":"立刻把那放高利貸的給我處理掉！我不想再見到她！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"당연히 그래야죠. 누구 명령이신데.","JPN":"はいはい、そうしますね。代表の命令ですから。","ENG":"You got it boss. Your wish is my command.","TWN":"當然囉，這可是代表的命令呢～"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 대신 함선에 실려 있던 융합체들, 써도 되지?","JPN":"その代わり、艦船に積んでいる融合体、使ってもいい？","ENG":"Does that mean I can use the hybriders on this ship?","TWN":"不過，艦船上的融合體可以用吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"리플레이서 융합체들 말이냐?","JPN":"リプレイサー融合体のことか？","ENG":"You mean the Replacer Hybriders?","TWN":"你是說克隆融合體？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그놈들은 통제 불능이야. 지휘관급 없이는 목줄 풀린 짐승들이란 말이다.","JPN":"あいつらは制御不能だ。指揮官級なしでは首輪の外れた獣同然だ。","ENG":"They're uncontrollable. They're nothing more than wild beasts without a Commander-class to lead them.","TWN":"那傢伙不受控的，如果沒有指揮官在場，他們就像脫韁的野馬一樣欸！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 대표님은 혹시 내가 누군지 잊은 거야?","JPN":"フフッ、もしかして代表は私が何者か忘れちゃったの？","ENG":"Haha, did you already forget who I am, boss?","TWN":"呵呵～代表，你忘了我是誰嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"융합체 같은 그럴싸한 말로 포장했을 뿐, 어차피 그것들도 침식체인걸.","JPN":"融合体なんてもっともらしい言葉で飾ってるだけで、どうせあれも侵食体なんだもの。","ENG":"They may have a fancy name like \\"hybrider\\", but at the end of the day, they're all C.O.s.","TWN":"融合體不過就是名字比較威風一點而已，實際上他們也不過就是侵蝕體。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼 쉬면서 느긋하게 감상하도록 해, 대표님.","JPN":"それじゃあ、そこでゆっくり鑑賞していてくださいね、代表。","ENG":"So just kick back and enjoy the show, boss.","TWN":"代表你就一邊休息，一邊欣賞演出吧～"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"나랑 저 애가 연주할 즉흥곡을 말이야.","JPN":"私とあの子が奏でる即興曲を。","ENG":"She and I are about to play the greatest impromptu duet you'll ever witness.","TWN":"是由我和他演奏的即興曲～"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"적대 개체들이 접근해 오지 않는군요. 경계 태세만 유지할 계획입니까.","JPN":"敵性個体が接近して来ませんね。警戒態勢だけ維持する方針ですか。","ENG":"The hostile units are not approaching me. Will you simply remain on guard?","TWN":"敵對個體沒有靠近，是打算維持緊戒狀態嗎？"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래야지. 저런 잔챙이들로 널 막을 생각은 안 하는 편이 좋을 테니까.","JPN":"そうよ。あんな雑魚であなたを止めるのはリスキーなんだから。","ENG":"Of course. It's not worth trying to stop you with such small fry.","TWN":"那當然囉～反正那些小咖也擋不住你～"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"셰나. 예상 시점보다 17시간 앞선 재대면이군요.","JPN":"シェナ。予想時刻より17時間早い再対面ですね。","ENG":"Shena. Based on my computations, I did not expect our next encounter for another 17 hours.","TWN":"世娜，我們重逢的時間比我預計的早17小時呢。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"물론이지. 청중의 예상을 멋지게 비껴 나가는 것도 즉흥곡의 묘미거든.","JPN":"もちろんよ。聴衆の予想を見事に外していくのも即興曲の醍醐味だもの。","ENG":"Of course. That's the whole point of an impromptu piece. You've got to expect the unexpected.","TWN":"一定要的，超出聽眾的期待，也算是即興曲的美妙之處呢～"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지금 시대의 인간들은 그런 미학을 이해할 교양도, 아량도 없지만.","JPN":"今の時代の人間たちは、そんな美学を理解する教養も雅量もないけれど。","ENG":"Then again, the humans in this era have neither the class nor patience to appreciate such subtle aesthetics.","TWN":"雖然現在的人都沒有欣賞這種美的修養和雅量。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼의 생존 여부를 알려 준 점은 고맙게 여기고 있습니다. 셰나.","JPN":"レイチェルの生存可否を教えてくれたことは感謝しています、シェナ。","ENG":"I do appreciate your notification that Rachel yet lives, Shena.","TWN":"世娜，我很感謝你告訴我瑞秋是生是死。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"채무를 변제할 목적으로, 당신과는 가능한 한 충돌하지 않고 싶군요.","JPN":"債務を返済する目的で、あなたとはできる限り衝突したくありません。","ENG":"For the purpose of repaying my debt, I would rather avoid any violent clashes with you.","TWN":"我的目的只是追討該償還的債務，可以的話並不想和你發生衝突。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"왜? 설마 날 배려해 주려는 거야?","JPN":"どうして？　まさか私に配慮してくれてるの？","ENG":"Why? Have you grown soft on me?","TWN":"為什麼？你該不會是在顧慮我吧？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"부정. 빚을 남겨 두는 건 제 알고리즘이 허락하지 않습니다.","JPN":"否定。借りを残しておくのは私のアルゴリズムが許しません。","ENG":"Negative. My algorithm simply does not permit to leave any debt unpaid.","TWN":"答錯。我的演算法不允許有未償還的債務。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 신기하기도 하지.","JPN":"フフッ……不思議だわ。","ENG":"Heh. How fascinating.","TWN":"呵呵～還真妙～"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이미 죽고 껍데기만 남았는데, 바뀐 주인도 예전이랑 별반 다를 바 없다니 말이야.","JPN":"すでに死んで抜け殻しか残っていないのに、新しい持ち主も以前とあまり変わらないなんて。","ENG":"You'd think it's nothing but a dead, empty shell… but the new occupant is no different from the previous tenant.","TWN":"明明就已經死掉只留下外殼，結果新的主人也和之前的一模一樣。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"무슨 말입니까. 상세한 설명을 요구하겠습니다.","JPN":"どういう意味でしょう。より詳しい説明を求めます。","ENG":"That does not compute. I must request you elucidate in detail.","TWN":"這是什麼意思？可以請你詳細說明嗎？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 잘난 프레임 말이야. 호라이즌.","JPN":"あなたのその立派なフレームのことよ、ホライズン。","ENG":"I'm talking about your fancy frame, Horizon.","TWN":"我是說你那厲害的軀殼，地平線。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"미안해. 머리에 우스꽝스럽게 생긴 장식을 달고 다녀서 처음에는 못 알아봤지 뭐야.","JPN":"ごめんね。その頭の滑稽な飾り付けのせいで、最初に会った時は気づかなかったわ。","ENG":"Sorry. I didn't recognize you at first with those silly things on your head.","TWN":"真是不好意思，因為你頭上那個滑稽的裝飾，所以一時沒認出你來。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……제 냉각기를 우스꽝스럽다고 판단한 것으로 보아 당신의 미학은 저와 상극이겠군요.","JPN":"……私の冷却器をおかしいと判断したことから、あなたの美学は私と相反するのでしょうね。","ENG":"…Judging by your assessment of my cooling devices as \\"silly things\\", I surmise your tastes are poorly aligned with mine.","TWN":"……你認為我的冷卻裝置很滑稽嗎？看來我們的美感差很多呢。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄, 싫어도 꾹 참고 한 곡 들으면 생각이 바뀌지 않을까?","JPN":"まあ、苦手でもぐっと我慢して一曲聴けば、考え方が変わるんじゃないかしら。","ENG":"Well, you might change your mind if you suck it up and hear this song?","TWN":"是嗎？說不定你聽我演奏完一曲後會改變想法喔？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"생체 정보 확인. 리플레이서 융합체 다수.","JPN":"生体情報確認。リプレイサー融合体複数。","ENG":"Biometrics identified. Multiple Replacer Hybriders detected.","TWN":"生物資訊確認，多個克隆融合體。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"통제실의 저장장치에 당신들이 무슨 짓을 저질렀는지 들어 있더군요.","JPN":"統制室のストレージにあなたたちが何をしたのか記録されていました。","ENG":"I found evidence of your antics in the control room's storage device.","TWN":"你們之前的所作所為，也都有記錄在控制室的儲存裝置裡。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"멘탈 프린팅이란 기술에 이렇게까지 해야 될 가치가 있습니까?","JPN":"メンタル・プリンティングという技術にそこまでする価値がありますか？","ENG":"Is this Mental Printing technology really worth wreaking such havoc?","TWN":"將智力複印的技術發展成這樣有值得嗎？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐, 누군가는 그렇게 받아들일지도 모르겠지만 나한테는 아니야.","JPN":"まあ、人によってはそんな捉え方をするのもあり得るけど、私は違うわ。","ENG":"Well, some might see it that way, but not me.","TWN":"對某些人而言可能是吧，但我不是。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"REPLACER_REPLACER_NULL_FUSION","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리에게 그건 살아가는 이유라고 해야 할까? 조금은 철학적인 이야기거든?","JPN":"私たちにとってあれは生きる理由といえばいいかしら？　ちょっと哲学的な話になるけど。","ENG":"You could say it's the very reason why we live. I'd love to explain, but it gets a tad philosophical.","TWN":"對我們來說，那是算是我們活下去的理由嗎？有點哲學理論～"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REPLACER_REPLACER_NULL_FUSION","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그러니 연주를 시작하자, 호라이즌. 트로피는 우리 대표님의 모가지야.","JPN":"だから演奏を始めましょう、ホライズン。トロフィーはうちの代表の首で。","ENG":"So let's just get this recital started, Horizon. As your trophy, I offer my boss's head.","TWN":"開始演奏吧，地平線！獎賞就是我們代表的項上人頭！"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"REPLACER_REPLACER_NULL_FUSION","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버가 당신들에게 그 정도로 중요한 인물입니까.","JPN":"ウィルバーがあなたたちにとってそんなに重要な人物ですか。","ENG":"Is Wilbur really such an important asset for you lot?","TWN":"韋爾伯對你來說有這麼重要嗎？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"손익도 계산할 줄 모르는 얼간이라기엔 황송할 정도의 취급이군요.","JPN":"損益も計算できないあの間抜けに、贅沢すぎる扱いですね。","ENG":"Such treatment is well beyond what that fool deserves. He cannot even properly conduct a profit-loss analysis.","TWN":"沒想到你是連損益都不懂得計算的傻瓜。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"조직이란 원래 조직원에 대한 공격을 조직에 대한 공격으로 받아들이는 법이야, 호라이즌.","JPN":"組織というのはね、組織員への攻撃は組織への攻撃として受け止めるものなのよ、ホライズン。","ENG":"That's just how organizations work, Horizon. We treat an attack on one of us as an attack on all of us.","TWN":"地平線，所謂的組織就是打狗也要看主人，攻擊組織成員，就等於是攻擊組織本身。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REPLACER_REPLACER_NULL_FUSION","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하물며 그 대상이 <color=#ffd34c>일단은</color> 조직의 대표자라고 한다면, 어쩔 수 없잖아?","JPN":"ましてやその対象が<color=#ffd34c>一応は</color>組織の代表者なら、仕方ないでしょ？","ENG":"Especially when that one person is the leader of the organization… <color=#ffd34c>for now</color>.","TWN":"更何況，你打的<color=#ffd34c>還是</color>組織的代表，能怎麼辦呢？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REPLACER_REPLACER_NULL_FUSION","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너희들의 편협한 현실세계에서 활동하려면, 우리 뜻을 대변해 줄 사람이 필요하거든.","JPN":"あなたたちの偏狭な現実世界で活動するには、私たちの意思を代弁してくれる人間が必要なの。","ENG":"You see, we need someone to serve as our representative if we are to operate in your provincial little Normalside.","TWN":"若想在你們那狹隘的現世中活動，就需要有能夠為我們發聲的人。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"REPLACER_REPLACER_NULL_FUSION","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"말단직원의 고충을 피력하셔도 제게는 통하지 않습니다.","JPN":"末端社員の苦労を訴えても私には通じません。","ENG":"I must point out I cannot empathize with your corporate affairs.","TWN":"雖然你表達出基層員工的心酸，但我不吃這套。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"새로 세울 대표나 어서 찾으러 가시죠, 셰나.","JPN":"代わりになる代表を探しておくことをおすすめします、シェナ。","ENG":"Your time will be better spent on finding a new chief executive officer, Shena.","TWN":"世娜，我看你還是趕快去找新的代表吧。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};